  const svelteSource: string = "// In your Svelte component:\nimport DataTableFoot from \"lily-design-system-svelte-headless/components/DataTableFoot/DataTableFoot.svelte\";\n\n<DataTableFoot>\n  <!-- DataTableFoot content -->\n</DataTableFoot>\n";
